#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""무료 자료 문서 본문(연습지·질문카드·프롬프트) — free/*.html은 build_site가 이 데이터로 생성. 수정은 여기서."""
DOCS={'worksheet': {'title': 'AI 대화 연습지', 'style': '\n.sheet{max-width:820px;margin:0 auto;padding:24px}\n.tbar{display:flex;gap:10px;justify-content:space-between;align-items:center;flex-wrap:wrap;margin-bottom:16px}\ntable.ws{width:100%;border-collapse:collapse;font-size:13px}\ntable.ws th,table.ws td{border:1.5px solid #C9BBA8;padding:10px 8px;vertical-align:top}\ntable.ws th{background:#F3E9D8;color:#5A4A32;font-weight:700;text-align:left}\ntable.ws td{height:56px}\n.ws-legend{display:flex;gap:8px;flex-wrap:wrap;margin:14px 0}\n.ws-legend span{background:#FBF6EE;border:1px solid #E4D8C4;border-radius:8px;padding:4px 10px;font-size:12.5px;color:#6b5a3e}\n@media print{.noprint{display:none!important}body{background:#fff}.sheet{padding:0}.hero-mini{box-shadow:none}}\n.hero-mini{background:linear-gradient(180deg,#FFF7EA,#FBF0DD);border:1px solid #EAD9BE;border-radius:16px;padding:20px 22px;margin-bottom:18px}\n', 'body': '\n<div class="sheet">\n<div class="hero-mini">\n<div style="font-size:40px">📝</div>\n<h1 style="margin:6px 0 4px;font-size:24px">집에서 하는 AI 대화 연습지</h1>\n<p style="margin:0;color:#6b5a3e">오늘 아이와 AI로 무엇을 했는지, <b>말하고 → 관찰하고 → 다시 묻는</b> 과정을 한 줄씩 적어보세요. 결과물이 아니라 \'다시 묻는 힘\'이 자랍니다.</p>\n</div>\n<div class="ws-legend noprint">\n<span>① 만들고 싶은 것을 <b>말로</b></span><span>② AI에게 <b>요청</b></span><span>③ 결과 <b>관찰</b></span><span>④ <b>다시</b> 묻기</span><span>⑤ 내 <b>생각</b></span>\n</div>\n<table class="ws"><thead><tr>\n<th style="width:12%">날짜</th><th style="width:20%">오늘 만들고 싶은 것<br><small style="font-weight:400">(아이 말로)</small></th>\n<th style="width:22%">AI에게 요청한 말</th><th style="width:15%">결과에서 좋은 점 /<br>이상한 점</th>\n<th style="width:18%">다시 물은 말</th><th style="width:13%">내 생각 /<br>배운 점</th>\n</tr></thead><tbody>\n<tr><td></td><td></td><td></td><td></td><td></td><td></td></tr>\n<tr><td></td><td></td><td></td><td></td><td></td><td></td></tr>\n<tr><td></td><td></td><td></td><td></td><td></td><td></td></tr>\n<tr><td></td><td></td><td></td><td></td><td></td><td></td></tr>\n<tr><td></td><td></td><td></td><td></td><td></td><td></td></tr>\n<tr><td></td><td></td><td></td><td></td><td></td><td></td></tr>\n<tr><td></td><td></td><td></td><td></td><td></td><td></td></tr>\n</tbody></table>\n<div class="hero-mini" style="margin-top:18px">\n<b>부모 팁</b> · 결과가 완벽하지 않아도 괜찮아요. 아이가 <b>"이상한 부분"을 스스로 찾고</b>, <b>"이렇게 바꿔줘"라고 다시 말하는 것</b>이 이 연습의 목표입니다.\n</div>\n<p class="center noprint" style="margin-top:18px"><a href="/free/question-cards.html" style="color:#E0684A;font-weight:700">→ 부모용 질문 카드도 받기</a> · <a href="/free/first-prompts.html" style="color:#E0684A;font-weight:700">첫 프롬프트 20개</a></p>\n<p class="center" style="color:#9b8a6e;font-size:12px;margin-top:20px">© 2026 AI조기교육 · ai-early-education.pages.dev</p>\n</div>'}, 'question-cards': {'title': '부모용 질문 카드 10장', 'style': '\n.sheet{max-width:900px;margin:0 auto;padding:24px}\n.tbar{display:flex;gap:10px;justify-content:space-between;align-items:center;flex-wrap:wrap;margin-bottom:16px}\n.cards{display:grid;grid-template-columns:repeat(2,1fr);gap:14px}\n.qc{border:2px dashed #C9BBA8;border-radius:14px;padding:16px 18px;background:#FFFDF9;position:relative;min-height:120px}\n.qc .tag{position:absolute;top:12px;right:14px;font-size:11px;background:#F3E9D8;color:#8a6f45;border-radius:8px;padding:2px 8px;font-weight:700}\n.qc .n{font-size:13px;color:#B9A98C;font-weight:800}\n.qc h3{margin:6px 0 6px;font-size:18px;line-height:1.35;color:#2B3A55}\n.qc p{margin:0;font-size:13px;color:#7c6a4d}\n.hero-mini{background:linear-gradient(180deg,#FFF7EA,#FBF0DD);border:1px solid #EAD9BE;border-radius:16px;padding:20px 22px;margin-bottom:18px}\n@media print{.noprint{display:none!important}body{background:#fff}.sheet{padding:0}.qc{break-inside:avoid}}\n@media(max-width:620px){.cards{grid-template-columns:1fr}}\n', 'body': '\n<div class="sheet">\n<div class="hero-mini">\n<div style="font-size:40px">🃏</div>\n<h1 style="margin:6px 0 4px;font-size:24px">부모용 질문 카드 10장</h1>\n<p style="margin:0;color:#6b5a3e">아이가 AI를 쓸 때 <b>이 한마디만</b> 건네보세요. 정답을 주는 대신, 아이가 스스로 <b>다시 묻게</b> 됩니다. 오려서 책상·냉장고에 붙여두세요.</p>\n</div>\n<div class="cards" id="cards"></div>\n<div class="hero-mini" style="margin-top:18px"><b>쓰는 법</b> · 한 번에 다 쓰지 마세요. 오늘은 딱 <b>한 장</b>만. 아이가 답하면 "왜 그렇게 생각해?"로 한 번 더 이어가면 충분합니다.</div>\n<p class="center noprint" style="margin-top:16px"><a href="/free/worksheet.html" style="color:#E0684A;font-weight:700">→ AI 대화 연습지</a> · <a href="/free/first-prompts.html" style="color:#E0684A;font-weight:700">첫 프롬프트 20개</a></p>\n<p class="center" style="color:#9b8a6e;font-size:12px;margin-top:18px">© 2026 AI조기교육 · ai-early-education.pages.dev</p>\n</div>\n<script>\nconst Q=[\n["검증","🔎 AI가 준 답에서 이상한 부분 하나만 찾아볼까?","AI도 틀린다는 걸 몸으로 배우는 첫 질문."],\n["검증","🔎 이 답이 진짜인지 어떻게 확인할 수 있을까?","근거를 찾는 습관을 만든다."],\n["주체성","🌱 AI 없이 너라면 어떻게 했을까?","아이 생각이 AI 뒤로 숨지 않게."],\n["주체성","🌱 방금 그건 네가 한 거야, AI가 한 거야?","무엇이 내 것인지 구분하게."],\n["다시묻기","🔁 왜 그렇게 답했는지 AI에게 다시 물어볼까?","한 번 더 묻는 힘을 기른다."],\n["다시묻기","🔁 이 답을 더 좋게 하려면 뭘 더 물어봐야 할까?","질문을 발전시키는 연습."],\n["의심","🛡️ AI도 틀릴 수 있을까? 언제 틀릴까?","맹신하지 않는 태도."],\n["의심","🛡️ 이 정보는 어디서 온 걸까?","출처를 묻는 습관."],\n["표현","💬 친구한테 설명한다면 어떻게 말할래?","이해한 걸 자기 말로."],\n["돌아보기","🌙 오늘 AI랑 뭐 했고, 뭘 다시 물어봤어?","하루를 스스로 정리하게."]];\ndocument.getElementById(\'cards\').innerHTML=Q.map((q,i)=>`<div class="qc"><span class="tag">${q[0]}</span><div class="n">Q${i+1}</div><h3>${q[1]}</h3><p>${q[2]}</p></div>`).join(\'\');\n</script>'}, 'first-prompts': {'title': '첫 프롬프트 20개', 'style': '\n.sheet{max-width:860px;margin:0 auto;padding:24px}\n.tbar{display:flex;gap:10px;justify-content:space-between;align-items:center;flex-wrap:wrap;margin-bottom:16px}\n.grp{margin:20px 0}\n.grp h2{font-size:17px;color:#2B3A55;border-left:4px solid #E0684A;padding-left:10px;margin:0 0 10px}\n.p{border:1px solid #E4D8C4;border-radius:12px;padding:12px 14px;margin-bottom:9px;background:#FFFDF9}\n.p .say{font-weight:700;color:#2B3A55}\n.p .again{margin-top:6px;font-size:13px;color:#9a6b45}\n.p .again b{color:#E0684A}\n.hero-mini{background:linear-gradient(180deg,#FFF7EA,#FBF0DD);border:1px solid #EAD9BE;border-radius:16px;padding:20px 22px;margin-bottom:18px}\n@media print{.noprint{display:none!important}body{background:#fff}.sheet{padding:0}.p{break-inside:avoid}}\n', 'body': '\n<div class="sheet">\n<div class="hero-mini">\n<div style="font-size:40px">💡</div>\n<h1 style="margin:6px 0 4px;font-size:24px">아이와 함께하는 첫 프롬프트 20개</h1>\n<p style="margin:0;color:#6b5a3e">처음 시작하기 좋은 프롬프트예요. 중요한 건 첫 요청이 아니라 <b>그다음 \'다시 묻기\'</b>입니다. 각 프롬프트 아래 <b style="color:#E0684A">🔁 다시 묻기</b>를 꼭 이어서 해보세요.</p>\n</div>\n<div id="groups"></div>\n<div class="hero-mini" style="margin-top:8px"><b>기억할 것</b> · 프롬프트는 마법 주문이 아니에요. <b>말하고 → 보고 → 다시 묻기</b>를 반복하는 대화가 진짜 실력을 만듭니다.</div>\n<p class="center noprint" style="margin-top:16px"><a href="/free/worksheet.html" style="color:#E0684A;font-weight:700">→ AI 대화 연습지</a> · <a href="/free/question-cards.html" style="color:#E0684A;font-weight:700">부모용 질문 카드</a></p>\n<p class="center" style="color:#9b8a6e;font-size:12px;margin-top:18px">© 2026 AI조기교육 · ai-early-education.pages.dev</p>\n</div>\n<script>\nconst G=[\n["🎨 그림 만들기",[\n["우주에서 피아노를 치는 고양이를 밤하늘 배경으로 그려줘","색을 딱 3가지만 써서 다시 그려줘"],\n["웃고 있는 강아지를 만화 스타일로, 파란 배경에 그려줘","강아지가 슬퍼 보이게 표정만 바꿔줘"],\n["우리 가족을 슈퍼히어로로 그려줘 (엄마·아빠·나)","나한테는 어떤 초능력이 어울릴지 이유도 알려줘"],\n["내가 좋아하는 공룡으로 생일 카드를 만들어줘","공룡이 케이크를 들고 있게 바꿔줘"],\n["비 오는 날 창밖 풍경을 따뜻한 느낌으로 그려줘","같은 장면을 밤으로 바꾸면 어떻게 달라질까?"]]],\n["📖 이야기 만들기",[\n["용감한 문어가 주인공인 짧은 동화를 만들어줘","문어가 무서워하는 게 있으면 하나 넣어줘"],\n["내 이름을 넣은 3문장짜리 모험 이야기를 써줘","결말을 완전히 다르게 하나 더 만들어줘"],\n["잠자기 전에 들려줄 다정한 이야기를 만들어줘","너무 길어. 5문장으로 줄여줘"],\n["로봇과 강아지가 친구가 되는 이야기","둘이 처음 만났을 때 무슨 말을 했을지 대사로 써줘"]]],\n["🔎 궁금한 것 물어보기",[\n["왜 하늘은 파란색이야? 초등학생도 알게 쉽게 설명해줘","방금 설명에서 어려운 단어 하나를 더 쉽게 바꿔줘"],\n["공룡은 왜 사라졌어? 3가지 이유를 알려줘","이 중에 확실한 건 뭐고, 아직 모르는 건 뭐야?"],\n["무지개는 어떻게 생겨? 그림으로 상상하게 설명해줘","집에서 무지개를 만들어보려면 뭐가 필요해?"],\n["재활용은 왜 중요할까? 우리 집에서 할 수 있는 것","오늘 당장 하나만 고른다면 뭘 추천해?"]]],\n["🧩 놀이·만들기",[\n["가족이 할 수 있는 끝말잇기 규칙을 재밌게 바꿔줘","5살 동생도 할 수 있게 더 쉽게 바꿔줘"],\n["종이접기로 만들 수 있는 쉬운 동물 하나 알려줘","접다가 어려운 부분은 어디일지 미리 알려줘"],\n["오늘 저녁 우리 가족 미니 퀴즈 5개 만들어줘","정답이 너무 쉬워. 한 문제만 어렵게 바꿔줘"],\n["비 오는 날 집에서 할 놀이 3가지 추천해줘","돈이 안 드는 걸로만 다시 골라줘"]]],\n["🤝 함께 검증하기",[\n["내가 쓴 이 문장을 더 자연스럽게 고쳐줘 (문장 붙여넣기)","어디를 왜 고쳤는지 이유도 알려줘"],\n["이 수학 문제 푸는 방법을 알려줘 (문제 붙여넣기)","정답만 말고, 내가 틀리기 쉬운 곳을 짚어줘"]]]\n];\ndocument.getElementById(\'groups\').innerHTML=G.map(([t,ps])=>`<div class="grp"><h2>${t}</h2>`+\n ps.map(p=>`<div class="p"><div class="say">"${p[0]}"</div><div class="again">🔁 <b>다시 묻기:</b> "${p[1]}"</div></div>`).join(\'\')+`</div>`).join(\'\');\n</script>'}}
